#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N, i, j, max, sum, F[1000001];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 1; i <= N; i++) {
            scanf("%d", &F[i]);
        }
        for (i = 1; i <= N; i++) {
            max = F[i];
            sum = 0;
            for (j = i; j <= N; j++) {
                if (F[j] > max) {
                    max = F[j];
                }
                sum += max;
            }
            for (j = 1; j <= N; j++) {
                if (j == i) {
                    continue;
                }
                if (F[j] == max) {
                    sum -= max;
                }
            }
            F[i] = (sum / (N - 1)) * N;
        }
        for (i = 1; i <= N; i++) {
            printf("%d ", F[i]);
        }
        printf("\n");
    }
    return 0;
}

